import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from "./componentes/TopoOferta";
import Rodape from "./componentes/Rodape";
import { buscarOfertasPromocao } from "./componentes/ofertasService";

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [etapa, setEtapa] = useState('vitrine'); 
  const [modoCadastro, setModoCadastro] = useState(false);
  const [formaPagamento, setFormaPagamento] = useState('');
  const [pedidoFinalizado, setPedidoFinalizado] = useState(null);
  const [historico, setHistorico] = useState([]);
  const [origemLogin, setOrigemLogin] = useState('checkout');
  const [formData, setFormData] = useState({ nome: '', email: '', senha: '', telefone: '', cep: '', endereco: '', cpf: '' });

  // Recupera usuário do localStorage com segurança
  const [usuario, setUsuario] = useState(() => {
    const salvo = localStorage.getItem('usuario_logado');
    return salvo ? JSON.parse(salvo) : null;
  });

  useEffect(() => {
    fetch("http://localhost:3001/produtos")
      .then(res => res.json())
      .then(dados => setProdutos(dados))
      .catch(err => console.error("Erro ao carregar produtos:", err));
  }, []);

  // --- LÓGICA DE PREÇOS ---
  const totalProd = carrinho.reduce((acc, i) => {
    const precoEfetivo = i.Desconto_10porct ? parseFloat(i.Desconto_10porct) : parseFloat(i.valor);
    return acc + (precoEfetivo * i.qtd);
  }, 0);

  const valorFrete = formaPagamento === 'pix' ? 0 : 15.00;

  // --- FUNÇÕES ---
  const adicionarAoCarrinho = (p) => {
    const itemExiste = carrinho.find(item => item.id === p.id);
    if (itemExiste) {
      setCarrinho(carrinho.map(item => item.id === p.id ? { ...item, qtd: item.qtd + 1 } : item));
    } else {
      setCarrinho([...carrinho, { ...p, qtd: 1 }]);
    }
  };

  const handleAuth = async () => {
    const rota = modoCadastro ? 'cadastrar' : 'login';
    try {
      const response = await fetch(`http://localhost:3001/${rota}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData)
      });
      const dados = await response.json();
      if (response.ok) {
        setUsuario(dados);
        localStorage.setItem('usuario_logado', JSON.stringify(dados));
        setEtapa(origemLogin === 'historico' ? 'historico' : 'checkout');
      } else {
        alert(dados.message);
      }
    } catch (err) {
      alert("Erro na conexão");
    }
  };

  const finalizar = async () => {
    const userAtual = usuario || JSON.parse(localStorage.getItem('usuario_logado'));
    if (!userAtual) return alert("Faça login novamente!");

    const numeroPedido = Math.floor(Math.random() * 100000);

    try {
      for (const item of carrinho) {
        const valorFinal = item.Desconto_10porct ? item.Desconto_10porct : item.valor;
        await fetch("http://localhost:3001/venda_cliente", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            id_pedido: numeroPedido,
            id_cliente: userAtual.id,
            produto: item.produto,
            quantidade: item.qtd,
            valor: valorFinal,
            id_produto: item.id
          })
        });
      }
      setPedidoFinalizado({ numero: numeroPedido });
      setCarrinho([]);
      setEtapa('sucesso');
    } catch (err) {
      alert("Erro ao finalizar");
    }
  };

  return (
    <div className="App">
      <Topo 
        totalItens={carrinho.length} 
        abrirCarrinho={() => setEtapa('carrinho')} 
        usuarioLogado={usuario} 
        setProdutos={setProdutos}
      />

      <main className="conteudo-principal">
        {etapa === 'vitrine' && (
          <div className="grid-produtos">
            {produtos.map(p => (
              <div key={p.id} className="card">
                <img src={p.imagem_url || p.foto} alt={p.produto} />
                <h3>{p.produto}</h3>
                <div className="preco-container">
                  {p.Desconto_10porct ? (
                    <>
                      <span className="preco-antigo" style={{textDecoration: 'line-through', color: 'gray'}}>R$ {parseFloat(p.valor).toFixed(2)}</span>
                      <span className="preco-novo" style={{color: 'red', fontWeight: 'bold', marginLeft: '10px'}}>R$ {parseFloat(p.Desconto_10porct).toFixed(2)}</span>
                    </>
                  ) : (
                    <span>R$ {parseFloat(p.valor).toFixed(2)}</span>
                  )}
                </div>
                <button onClick={() => adicionarAoCarrinho(p)}>Comprar</button>
              </div>
            ))}
          </div>
        )}

        {etapa === 'carrinho' && (
          <div className="container-venda">
            <h2>Carrinho</h2>
            {carrinho.map(item => (
              <div key={item.id} className="item-carrinho">
                <p>{item.produto} - R$ {parseFloat(item.Desconto_10porct || item.valor).toFixed(2)} x {item.qtd}</p>
              </div>
            ))}
            <h3>Total: R$ {totalProd.toFixed(2)}</h3>
            <button onClick={() => setEtapa(usuario ? 'checkout' : 'login')}>Finalizar</button>
            <button onClick={() => setEtapa('vitrine')}>Voltar</button>
          </div>
        )}

        {etapa === 'login' && (
          <div className="container-venda">
            <h2>Login</h2>
            <input placeholder="E-mail" onChange={e => setFormData({...formData, email: e.target.value})} />
            <input type="password" placeholder="Senha" onChange={e => setFormData({...formData, senha: e.target.value})} />
            <button onClick={handleAuth}>Entrar</button>
          </div>
        )}

        {etapa === 'checkout' && (
          <div className="container-venda">
            <h2>Checkout</h2>
            <select onChange={e => setFormaPagamento(e.target.value)}>
              <option value="">Forma de Pagamento</option>
              <option value="pix">Pix (Frete Grátis)</option>
              <option value="cartao">Cartão</option>
            </select>
            <p>Frete: R$ {valorFrete.toFixed(2)}</p>
            <h3>Total: R$ {(totalProd + valorFrete).toFixed(2)}</h3>
            <button onClick={finalizar}>Confirmar Pedido</button>
          </div>
        )}

        {etapa === 'sucesso' && (
          <div className="alerta-s">
            <h2>Pedido #{pedidoFinalizado?.numero} realizado!</h2>
            <button onClick={() => setEtapa('vitrine')}>Voltar ao início</button>
          </div>
        )}
      </main>
      <Rodape />
    </div>
  );
}

export default App;
